import numpy as np
from statsmodels.tsa.holtwinters import ExponentialSmoothing

def fit_holt_winters(y, trend='add', seasonal='add', seasonal_periods=12):
    model = ExponentialSmoothing(
        y, trend=trend, seasonal=seasonal,
        seasonal_periods=seasonal_periods,
    )
    return model.fit()

def forecast(result, steps=12):
    return result.forecast(steps)
